using namespace std;

bool solve(vector<long long> nums) {
    int n = nums.size();
    if (n < 3) {
        return false;
    }

    vector<bool> prefix_inc(n, false);
    prefix_inc[0] = true;
    for (int i = 1; i < n; i++) {
